'use strict';

// MODULES //

import ndarraylike2scalar from '@stdlib/ndarray-base-ndarraylike2scalar';
import numelDimension from '@stdlib/ndarray-base-numel-dimension';
import getStride from '@stdlib/ndarray-base-stride';
import getOffset from '@stdlib/ndarray-base-offset';
import getData from '@stdlib/ndarray-base-data-buffer';
import { ndarray as strided } from '@stdlib/blas-ext-base-gsort';


// MAIN //

/**
* Sorts a one-dimensional ndarray.
*
* @param {ArrayLikeObject<Object>} arrays - array-like object containing a one-dimensional input ndarray and a zero-dimensional ndarray specifying the sort order
* @returns {Object} input ndarray
*
* @example
* import array from '@stdlib/ndarray-array';
* import scalar2ndarray from '@stdlib/ndarray-from-scalar';
*
* var x = array( [ 1.0, -2.0, 3.0, -4.0 ], {
*    'dtype': 'generic'
* });
* // returns <ndarray>[ 1.0, -2.0, 3.0, -4.0 ]
*
* var ord = scalar2ndarray( 1.0, {
*    'dtype': 'generic'
* });
* // returns <ndarray>[ 1.0 ]
*
* var out = gsort( [ x, ord ] );
* // returns <ndarray>[ -4.0, -2.0, 1.0, 3.0 ]
*/
function gsort( arrays ) {
	var ord;
	var x;

	x = arrays[ 0 ];
	ord = ndarraylike2scalar( arrays[ 1 ] );
	strided( numelDimension( x, 0 ), ord, getData( x ), getStride( x, 0 ), getOffset( x ) ); // eslint-disable-line max-len
	return x;
}


// EXPORTS //

export default gsort;
