'use strict';

// MODULES //

import ndarraylike2scalar from '@stdlib/ndarray-base-ndarraylike2scalar';
import numelDimension from '@stdlib/ndarray-base-numel-dimension';
import getStride from '@stdlib/ndarray-base-stride';
import getOffset from '@stdlib/ndarray-base-offset';
import getData from '@stdlib/ndarray-base-data-buffer';
import { ndarray as strided } from '@stdlib/blas-ext-base-gjoin-between';


// MAIN //

/**
* Returns a string by joining one-dimensional ndarray elements using a specified separator for each pair of consecutive elements.
*
* @param {ArrayLikeObject<Object>} arrays - array-like object containing ndarrays
* @returns {string} joined string
*
* @example
* import ndarray from '@stdlib/ndarray-base-ctor';
* import scalar2ndarray from '@stdlib/ndarray-from-scalar';
*
* var xbuf = [ 1, 2, 3, 4 ];
* var x = new ndarray( 'generic', xbuf, [ 4 ], [ 1 ], 0, 'row-major' );
*
* var prefix = scalar2ndarray( 'op: ', {
*     'dtype': 'generic'
* });
*
* var suffix = scalar2ndarray( '', {
*     'dtype': 'generic'
* });
*
* var sbuf = [ ' + ', ' - ', ' != ' ];
* var separators = new ndarray( 'generic', sbuf, [ 3 ], [ 1 ], 0, 'row-major' );
*
* var v = gjoinBetween( [ x, prefix, suffix, separators ] );
* // returns 'op: 1 + 2 - 3 != 4'
*/
function gjoinBetween( arrays ) {
	var separators;
	var prefix;
	var suffix;
	var x;

	x = arrays[ 0 ];
	prefix = ndarraylike2scalar( arrays[ 1 ] );
	suffix = ndarraylike2scalar( arrays[ 2 ] );
	separators = arrays[ 3 ];
	return strided( numelDimension( x, 0 ), prefix, suffix, getData( x ), getStride( x, 0 ), getOffset( x ), getData( separators ), getStride( separators, 0 ), getOffset( separators ) ); // eslint-disable-line max-len
}


// EXPORTS //

export default gjoinBetween;
